// Parse Congruent Ventures - portfolio page with company links
const items = $input.all();
const results = [];
const vcName = 'Congruent Ventures';
const seen = new Set();
const today = new Date().toISOString().split('T')[0];

for (const item of items) {
  let html = item.json.data || (typeof item.json === 'string' ? item.json : JSON.stringify(item.json));

  // Pattern: /portfolio/Company-Name links
  const slugPattern = /href=["']\/portfolio\/([A-Za-z0-9\-\.]+)["']/gi;
  let match;

  while ((match = slugPattern.exec(html)) !== null) {
    const slug = match[1].trim();
    if (!slug || slug.length < 2) continue;
    if (slug.toLowerCase() === 'portfolio') continue;

    // Convert slug to company name (replace hyphens with spaces, capitalize)
    let name = slug.replace(/-/g, ' ').replace(/\./g, ' ');
    name = name.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()).join(' ');

    const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
    if (seen.has(key)) continue;
    seen.add(key);

    results.push({ json: { 'Company Name': name, 'VC Firm': vcName, 'Company Description': `${name} - Congruent Ventures portfolio company (climate tech)`, 'Company URL': `https://www.congruentvc.com/portfolio/${slug}`, 'Status': 'New', 'First Seen Date': today, 'Portfolio Addition Date': today, 'Source': 'VC Portfolio' } });
  }
}
return results.length ? results : [{ json: { _empty: true, _message: 'No companies found', vcName } }];

