  // Pattern: <h3>Company Name</h3> followed by SINCE YEAR
  const companyPattern = /<h3[^>]*>([A-Za-z0-9\s\-&\.]+)<\/h3>\s*<p[^>]*>SINCE\s+(\d{4})/gi;
