    seen.add(key);

    // Look for website link nearby
    const context = html.substring(match.index, Math.min(html.length, match.index + 1500));
    let url = '';
    const urlMatch = context.match(/VISIT WEBSITE[^<]*<\/a>\s*<a[^>]*href=["'](https?:\/\/[^"']+)["']/i) ||
                     context.match(/href=["'](https?:\/\/(?!energizecap|linkedin|twitter|facebook)[^"']+)["'][^>]*>.*?VISIT/i);
