// Parse Burnt Island Ventures - water-focused fund with marquee and logo grid
const items = $input.all();
const results = [];
const vcName = 'Burnt Island Ventures';
const seen = new Set();
const today = new Date().toISOString().split('T')[0];

// Skip these domains
const skipDomains = ['burntisland', 'squarespace', 'linkedin', 'twitter', 'facebook', 'cdn', 'google'];

for (const item of items) {
  let html = item.json.data || (typeof item.json === 'string' ? item.json : JSON.stringify(item.json));

  // Pattern 1: External company links (logo grid)
  const linkPattern = /<a[^>]*href=["'](https?:\/\/(?!burntisland|squarespace|linkedin|twitter|facebook)[^"']+)["'][^>]*>/gi;
  let match;

  while ((match = linkPattern.exec(html)) !== null) {
    const url = match[1].trim();
    if (url.includes('#') || url.includes('sqs') || url.includes('cdn')) continue;

    // Extract domain as company name
    const domainMatch = url.match(/https?:\/\/(?:www\.)?([^.\/]+)/i);
    if (!domainMatch) continue;

    let name = domainMatch[1];
    name = name.charAt(0).toUpperCase() + name.slice(1);
    name = name.replace(/ai$/i, 'AI');

    const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
    if (key.length < 2 || seen.has(key)) continue;
    if (skipDomains.some(d => key.includes(d))) continue;
    seen.add(key);

    results.push({ json: { 'Company Name': name, 'VC Firm': vcName, 'Company Description': `${name} - Burnt Island Ventures portfolio company (water tech)`, 'Company URL': url, 'Status': 'New', 'First Seen Date': today, 'Portfolio Addition Date': today, 'Source': 'VC Portfolio' } });
  }

  // Pattern 2: Marquee text items (company names in spans)
  const marqueePattern = /class=["'][^"']*marquee[^"']*["'][^>]*>([^<]+)</gi;
  while ((match = marqueePattern.exec(html)) !== null) {
    let name = match[1].trim();
    if (!name || name.length < 2 || name.length > 60) continue;

    const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
    if (key.length < 2 || seen.has(key)) continue;
    seen.add(key);

    results.push({ json: { 'Company Name': name, 'VC Firm': vcName, 'Company Description': `${name} - Burnt Island Ventures portfolio company (water tech)`, 'Company URL': '', 'Status': 'New', 'First Seen Date': today, 'Portfolio Addition Date': today, 'Source': 'VC Portfolio' } });
  }
}
return results.length ? results : [{ json: { _empty: true, _message: 'No companies found', vcName } }];

