// v26: Filter companies already in Seen Opportunities or Funding Alerts
const items = $input.all();
const staticData = $getWorkflowStaticData("global");
const seenKeys = new Set(staticData.seenCompanyKeys || []);
const localSeen = new Set();
const newCompanies = [];
let skipped = 0;

for (const item of items) {
  if (item.json._empty) continue;
  const name = item.json["Company Name"] || "";
  if (!name || name.length < 2) continue;

  const localKey = name.toLowerCase().replace(/[^a-z0-9]/g, "");
  if (localSeen.has(localKey)) { skipped++; continue; }
  localSeen.add(localKey);

  const dedupKey = "company:" + localKey;
  if (seenKeys.has(dedupKey)) { skipped++; continue; }

  newCompanies.push(item);
}

console.log(`v26 Filter: ${skipped} already seen, ${newCompanies.length} NEW`);
if (newCompanies.length === 0) {
  return [{ json: { _empty: true, _message: "All companies already processed", skipped } }];
}
return newCompanies;

// v26: Store seen company keys from BOTH Seen Opportunities and Funding Alerts
const staticData = $getWorkflowStaticData("global");
const seenKeys = new Set();
const items = $input.all();

for (const item of items) {
  const key = item.json.Key;
  if (key && key.startsWith("company:")) {
    seenKeys.add(key);
    continue;
  }
  const companyName = item.json["Company Name"];
  if (companyName) {
    const normalizedKey = "company:" + companyName.toLowerCase().replace(/[^a-z0-9]/g, "");
    seenKeys.add(normalizedKey);
  }
}

staticData.seenCompanyKeys = Array.from(seenKeys);
console.log(`v26: Stored ${seenKeys.size} seen company keys`);
return [{ json: { seenKeysLoaded: true, count: seenKeys.size } }];
